"$:/plugins/JorisL/Texify/styles/texify.css": {
    "created": "20260314215344165",
    "text": "{{$:/plugins/JorisL/Texify/settings/css-selector}} {
    font-family: {{$:/plugins/JorisL/Texify/settings/font-family}};
		.tc-tiddler-body {
				font-size: {{$:/plugins/JorisL/Texify/settings/font-size}};
				max-width: {{$:/plugins/JorisL/Texify/settings/max-width}};
				margin: 0 auto;
				/*column-count: 2;*/
				p {
						text-align: justify;
						hyphens: auto;
				}
				a {
						overflow-wrap: break-word;
						hyphens: none;
						line-break: anywhere;
				}

				/* LaTeX-like Table Styling for tables*/
				table {
						border-collapse: collapse;
						border: initial;
				}
				thead {
						border-top: 1px solid;
						border-bottom: 1px solid;
				}
				tbody {
						border-bottom: 1px solid;
				}
				tfoot {
						border-bottom: 1px solid;
				}
				th,td {
						padding: 0.5em;
						text-align: left;
						border: none;
						background-color: transparent;
				}
				th {
						border-bottom: 1px solid;
						background-color: transparent;
				}
				tfoot td {
						border-top: 1px solid;
						background-color: transparent;

				}

				/* Auto number headings */
				counter-set: h1 h2 h3 h4 h5 h6

		}

		/* Auto number headings */
		.tc-tiddler-body > h1 {
				counter-set: h2
		}
		.tc-tiddler-body > h2 {
				counter-set: h3
		}
		.tc-tiddler-body > h3 {
				counter-set: h4
		}
		.tc-tiddler-body > h4 {
				counter-set: h5
		}
		.tc-tiddler-body > h5 {
				counter-set: h6
		}

		/** put counter result into headings */
		.tc-tiddler-body > h1:before {
				counter-increment: h1;
				/*content: "";*/
				content: counter(h1) " ";
		}
		.tc-tiddler-body > h2:before {
				counter-increment: h2;
				content: counter(h1) "." counter(h2) " "
		}
		.tc-tiddler-body > h3:before {
				counter-increment: h3;
				content: counter(h1) "." counter(h2) "." counter(h3) " "
		}
		.tc-tiddler-body > h4:before{
				counter-increment: h4;
				content: counter(h1) "." counter(h2) "." counter(h3) "." counter(h4) " "
		}
		.tc-tiddler-body >  h5:before {
				counter-increment: h5;
				content: counter(h1) "." counter(h2) "." counter(h3) "." counter(h4) "." counter(h5) " "
		}
		.tc-tiddler-body > h6:before {
				counter-increment: h6;
				content: counter(h1) "." counter(h2) "." counter(h3) "." counter(h4) "." counter(h5) "." counter(h6) " "
		}

		/* todo: excemptions for text fields, buttons, etc. */
}",
    "title": "$:/plugins/JorisL/Texify/styles/texify.css",
